mapper.select:
SELECT D.PK_NO, D.PERSON_ID, HE.EMPID, HE.LOCAL_NAME, GET_DEPT_NAME(D.DEPT_NO, #{lang, jdbcType=VARCHAR}) AS DEPT_NAME, D.ITEM_NO, get_global_name(D.ITEM_NO, #{lang, jdbcType=VARCHAR}) AS ITEM_NAME, D.SHIFT_NO, GET_GLOBAL_NAME(D.SHIFT_NO, #{lang, jdbcType=VARCHAR}) AS SHIFT_NAME, D.AR_DATE_STR, TO_CHAR(D.FROM_TIME, 'HH24:MI') || ' ~ ' || TO_CHAR(D.TO_TIME, 'HH24:MI') AS WORK_TIME, TO_CHAR(D.FROM_TIME, 'HH24:MI') AS INDOOR_TIME, TO_CHAR(D.TO_TIME, 'HH24:MI') AS OUTDOOR_TIME, TO_CHAR(D.FROM_TIME, 'DD/MM/YYYY HH24:MI') AS OT_START_TIME, TO_CHAR(D.TO_TIME, 'DD/MM/YYYY HH24:MI') AS OT_END_TIME, D.QUANTITY FROM AR_DETAIL_HFSV D JOIN HR_EMPLOYEE HE ON HE.PERSON_ID = D.PERSON_ID WHERE D.PERSON_ID = #{adminID, jdbcType=VARCHAR} AND D.ITEM_NO IN ( SELECT AIP.ITEM_NO FROM AR_ITEM_PARAM AIP JOIN AR_ITEM AI ON AI.ITEM_NO = AIP.ITEM_NO WHERE AIP.CPNY_ID = #{cpnyId, jdbcType=VARCHAR} AND AI.ITEM_GROUP_CODE = '1433' )
AND D.AR_DATE_STR >= TO_CHAR(TO_DATE(#{startDate, jdbcType=VARCHAR}, 'DD/MM/YYYY'), 'YYYY/MM/DD')
AND D.AR_DATE_STR <= TO_CHAR(TO_DATE(#{endDate, jdbcType=VARCHAR}, 'DD/MM/YYYY'), 'YYYY/MM/DD')
AND D.ITEM_NO = #{itemNoSearch, jdbcType=VARCHAR}
AND D.QUANTITY >= #{minQuantity, jdbcType=VARCHAR}
ORDER BY D.AR_DATE_STR DESC, D.ITEM_NO
